#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e5+5;
int k,n,a[MAXN],cf[MAXN],ans=0;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&k,&n);
	for(int i=1;i<=n;++i)
	{
		scanf("%d",a+i);
	}
	sort(a+1,a+n+1);
	for(int i=2;i<=n;++i)
	{
		cf[i-1]=a[i]-a[i-1];
	}
	sort(cf+1,cf+n);
	for(int i=1;i<=n-k;++i)ans+=cf[i];
	printf("%d",ans);
	return false;
}
